from qiskit import QuantumCircuit

def build():
    qc = QuantumCircuit(3)
    qc.x(0)
    qc.x(2)
    return qc

calls = {
    "A": lambda qc: qc.draw("text", idle_wires=True),
    "B": lambda qc: qc.draw("text", idle_wires=False),
    "C": lambda qc: qc.draw("text", plot_barriers=False),
    "D": lambda qc: qc.draw("text", reverse_bits=True),
}
evidence = {}
proven = []
for k, fn in calls.items():
    try:
        txt = str(fn(build()))
        q1_present = "q_1" in txt
        hides_idle = not q1_present
        evidence[k] = (
            f"rendered OK; qubit-1 wire present={q1_present}; "
            f"hides idle q1={hides_idle}"
        )
        if hides_idle:
            proven.append(k)
    except Exception as e:
        evidence[k] = f"raised {type(e).__name__}: {str(e)[:90]}"

emit_verdict({
    "answer": proven,
    "evidence": evidence,
    "observed": {"idle_false_drawing": str(build().draw('text', idle_wires=False))},
})
